module johnson_counter (
    input clk,
    input reset,
    output [4:0] q );reg [4:0] unused_count_reg;

always @(posedge clk) begin
    if (reset)
        unused_count_reg <= 5'b00000;
    else
        unused_count_reg <= {unused_count_reg[3:0], ~unused_count_reg[4]};
end

assign q = unused_count_reg;

endmodule
